import pytest
from urllib.parse import urlparse, urlunparse

def test_urldefragauth_with_authentication():
    url = "http://user:pass@example.com/path?query#fragment"
    assert urldefragauth(url) == "http://example.com/path?query"

def test_urldefragauth_without_authentication():
    url = "http://example.com/path?query#fragment"
    assert urldefragauth(url) == "http://example.com/path?query"

def test_urldefragauth_with_no_fragment():
    url = "http://example.com/path?query"
    assert urldefragauth(url) == "http://example.com/path?query"

def test_urldefragauth_with_empty_fragment():
    url = "http://example.com/path?query#"
    assert urldefragauth(url) == "http://example.com/path?query"

def test_urldefragauth_with_no_netloc():
    url = "/path?query#fragment"
    assert urldefragauth(url) == "/path?query"

def test_urldefragauth_with_only_fragment():
    url = "#fragment"
    assert urldefragauth(url) == ""

def test_urldefragauth_with_scheme_only():
    url = "http://"
    assert urldefragauth(url) == "http://"

def test_urldefragauth_with_invalid_url():
    url = "invalid_url"
    with pytest.raises(ValueError):
        urldefragauth(url)

def test_urldefragauth_with_special_characters():
    url = "http://user:pass@ex@mple.com/path?query#fragment"
    assert urldefragauth(url) == "http://ex@mple.com/path?query"

def test_urldefragauth_with_multiple_authentication_parts():
    url = "http://user:pass@user2:pass2@example.com/path?query#fragment"
    assert urldefragauth(url) == "http://example.com/path?query"

