import pytest
from requests.exceptions import JSONDecodeError
from your_module import YourClass  # Replace with the actual class name

@pytest.fixture
def response():
    return YourClass()  # Initialize your class here

def test_json_valid_dict(response):
    response.content = b'{"key": "value"}'
    assert response.json() == {"key": "value"}

def test_json_valid_list(response):
    response.content = b'[1, 2, 3]'
    assert response.json() == [1, 2, 3]

def test_json_empty_content(response):
    response.content = b''
    with pytest.raises(JSONDecodeError):
        response.json()

def test_json_invalid_json(response):
    response.content = b'{"key": "value",}'
    with pytest.raises(JSONDecodeError):
        response.json()

def test_json_no_encoding(response):
    response.content = b'{"key": "value"}'
    response.encoding = None
    assert response.json() == {"key": "value"}

def test_json_unicode_decode_error(response):
    response.content = b'\xff\xfe{"key": "value"}'  # Invalid UTF-16
    response.encoding = None
    with pytest.raises(JSONDecodeError):
        response.json()

def test_json_fallback_to_text(response):
    response.text = '{"key": "value"}'
    response.content = b'not json'
    assert response.json() == {"key": "value"}

def test_json_with_kwargs(response):
    response.content = b'{"key": "value"}'
    assert response.json(object_pairs_hook=dict) == {"key": "value"}

def test_json_large_content(response):
    response.content = b'[' + b'{"key": "value"},' * 1000 + b']'
    assert response.json() == [{"key": "value"}] * 1000

def test_json_invalid_utf8(response):
    response.content = b'\x80\x81\x82'  # Invalid UTF-8
    response.encoding = None
    with pytest.raises(JSONDecodeError):
        response.json()

