    result = formatter.describe_multi([])
    assert result == ""

def test_describe_multi_only_distance_empty(formatter):
    result = formatter.describe_multi([], only_distance=True)
    assert result == ""

def test_describe_multi_large_numbers(formatter):
    result = formatter.describe_multi([("years", 1000), ("days", 365)])
    assert result == "1000 years and 365 days ago"

