def _format_timeframe(self, timeframe: TimeFrameLiteral, delta: int) -> str:
    form = self.timeframes[timeframe]
    delta = abs(delta)
    if isinstance(form, Mapping):
        if delta == 2:
            form = form["2"]
        elif delta == 0 or 2 < delta <= 10:
            form = form["ten"]
        else:
            form = form["higher"]

    return form.format(delta)

