import pytest

MAX_TIMESTAMP = 2**31 - 1  # Example max timestamp for seconds
MAX_TIMESTAMP_MS = MAX_TIMESTAMP * 1000
MAX_TIMESTAMP_US = MAX_TIMESTAMP * 1_000_000

def test_normalize_timestamp_seconds():
    assert normalize_timestamp(1622548800.0) == 1622548800.0

def test_normalize_timestamp_milliseconds():
    assert normalize_timestamp(1622548800000.0) == 1622548800.0

def test_normalize_timestamp_microseconds():
    assert normalize_timestamp(1622548800000000.0) == 1622548800.0

def test_normalize_timestamp_large_milliseconds():
    result = normalize_timestamp(MAX_TIMESTAMP_MS - 1)
    assert result == (MAX_TIMESTAMP_MS - 1) / 1000

def test_normalize_timestamp_large_microseconds():
    result = normalize_timestamp(MAX_TIMESTAMP_US - 1)
    assert result == (MAX_TIMESTAMP_US - 1) / 1_000_000

def test_normalize_timestamp_too_large():
    with pytest.raises(ValueError, match="The specified timestamp"):
        normalize_timestamp(MAX_TIMESTAMP_US + 1)

