import pytest
from collections import Counter
from itertools import chain

def unique_to_each(*iterables):
    pool = [list(it) for it in iterables]
    counts = Counter(chain.from_iterable(map(set, pool)))
    uniques = {element for element in counts if counts[element] == 1}
    return [list(filter(uniques.__contains__, it)) for it in pool]

def test_unique_to_each_basic():
    result = unique_to_each({'A', 'B'}, {'B', 'C'}, {'B', 'D'})
    assert result == [['A'], ['C'], ['D']]

def test_unique_to_each_with_duplicates():
    result = unique_to_each("mississippi", "missouri")
    assert result == [['p', 'p'], ['o', 'u', 'r']]

def test_unique_to_each_empty_iterables():
    result = unique_to_each([], [], [])
    assert result == [[], [], []]

def test_unique_to_each_single_iterable():
    result = unique_to_each({'A', 'B', 'C'})
    assert result == [['A', 'B', 'C']]

def test_unique_to_each_no_uniques():
    result = unique_to_each({'A', 'B'}, {'A', 'B'})
    assert result == [[], []]

def test_unique_to_each_all_uniques():
    result = unique_to_each({'A'}, {'B'}, {'C'})
    assert result == [['A'], ['B'], ['C']]

def test_unique_to_each_mixed_types():
    result = unique_to_each({1, 2}, {2.0, 3}, {'3', 4})
    assert result == [[1], [3], [4]]

def test_unique_to_each_large_input():
    result = unique_to_each(range(1000), range(500, 1500), range(1000, 2000))
    assert result[0] == list(range(500))  # Unique to first iterable
    assert result[1] == list(range(500, 1000))  # Unique to second iterable
    assert result[2] == list(range(1000, 1500))  # Unique to third iterable

def test_unique_to_each_non_hashable_elements():
    with pytest.raises(TypeError):
        unique_to_each([{1}, {2}], [{2}])

def test_unique_to_each_nested_iterables():
    result = unique_to_each([{1, 2}, {2, 3}], [{3, 4}, {4, 5}])
    assert result == [[1], [4], [5]]

