import pytest

class TestIndex:
    @pytest.fixture
    def index_instance(self):
        class Index:
            def __init__(self, start, stop, step):
                self._start = start
                self._stop = stop
                self._step = step
                self._zero = 0
                self._growing = True if step > 0 else False

            def index(self, value):
                if self._growing:
                    if self._start <= value < self._stop:
                        q, r = divmod(value - self._start, self._step)
                        if r == self._zero:
                            return int(q)
                else:
                    if self._start >= value > self._stop:
                        q, r = divmod(self._start - value, -self._step)
                        if r == self._zero:
                            return int(q)

                raise ValueError(f"{value} is not in numeric range")

        return Index

    def test_index_growing_within_range(self, index_instance):
        instance = index_instance(0, 10, 2)
        assert instance.index(2) == 1
        assert instance.index(4) == 2
        assert instance.index(6) == 3
        assert instance.index(8) == 4

    def test_index_growing_outside_range(self, index_instance):
        instance = index_instance(0, 10, 2)
        with pytest.raises(ValueError, match="10 is not in numeric range"):
            instance.index(10)
        with pytest.raises(ValueError, match="-1 is not in numeric range"):
            instance.index(-1)

    def test_index_growing_exact_start(self, index_instance):
        instance = index_instance(0, 10, 2)
        assert instance.index(0) == 0

    def test_index_growing_exact_stop(self, index_instance):
        instance = index_instance(0, 10, 2)
        with pytest.raises(ValueError, match="10 is not in numeric range"):
            instance.index(10)

    def test_index_decreasing_within_range(self, index_instance):
        instance = index_instance(10, 0, -2)
        assert instance.index(8) == 1
        assert instance.index(6) == 2
        assert instance.index(4) == 3
        assert instance.index(2) == 4

    def test_index_decreasing_outside_range(self, index_instance):
        instance = index_instance(10, 0, -2)
        with pytest.raises(ValueError, match="0 is not in numeric range"):
            instance.index(0)
        with pytest.raises(ValueError, match="12 is not in numeric range"):
            instance.index(12)

    def test_index_decreasing_exact_start(self, index_instance):
        instance = index_instance(10, 0, -2)
        assert instance.index(10) == 0

    def test_index_decreasing_exact_stop(self, index_instance):
        instance = index_instance(10, 0, -2)
        with pytest.raises(ValueError, match="0 is not in numeric range"):
            instance.index(0)

    def test_index_invalid_step(self, index_instance):
        instance = index_instance(0, 10, 0)
        with pytest.raises(ValueError, match="0 is not in numeric range"):
            instance.index(0)

